import { useCallback, useEffect, useState } from 'react';

type Todo = { id: string; title: string; done: boolean; createdAt: string };

export default function App() {
  const [todos, setTodos] = useState<Todo[]>([]);
  const [title, setTitle] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);

  const load = useCallback(async () => {
    setError(null);
    const res = await fetch('/api/todos');
    if (!res.ok) {
      setError(`Failed to load (${res.status}). Is the API running?`);
      setTodos([]);
      return;
    }
    const data = await res.json();
    setTodos(data.todos ?? []);
  }, []);

  useEffect(() => {
    load().finally(() => setLoading(false));
  }, [load]);

  async function add(e: React.FormEvent) {
    e.preventDefault();
    if (!title.trim()) return;
    setError(null);
    const res = await fetch('/api/todos', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ title: title.trim() }),
    });
    if (!res.ok) {
      setError('Could not create todo');
      return;
    }
    setTitle('');
    await load();
  }

  async function toggle(t: Todo) {
    await fetch(`/api/todos/${t.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ done: !t.done }),
    });
    await load();
  }

  async function remove(t: Todo) {
    await fetch(`/api/todos/${t.id}`, { method: 'DELETE' });
    await load();
  }

  return (
    <div style={{ maxWidth: 520, margin: '0 auto', padding: '2rem 1rem' }}>
      <h1 style={{ fontSize: '1.5rem', marginBottom: '0.5rem' }}>Todos</h1>
      <p style={{ color: '#94a3b8', fontSize: '0.9rem', marginBottom: '1.5rem' }}>
        Vite → proxy → Express → Prisma → SQLite (<code>backend/prisma/dev.db</code>)
      </p>

      <form onSubmit={add} style={{ display: 'flex', gap: 8, marginBottom: '1.25rem' }}>
        <input
          value={title}
          onChange={(e) => setTitle(e.target.value)}
          placeholder="New task…"
          style={{
            flex: 1,
            padding: '0.6rem 0.75rem',
            borderRadius: 8,
            border: '1px solid #334155',
            background: '#1e293b',
            color: '#f8fafc',
          }}
        />
        <button
          type="submit"
          style={{
            padding: '0.6rem 1rem',
            borderRadius: 8,
            border: 'none',
            background: '#38bdf8',
            color: '#0f172a',
            fontWeight: 600,
            cursor: 'pointer',
          }}
        >
          Add
        </button>
      </form>

      {loading && <p>Loading…</p>}
      {error && (
        <p style={{ color: '#f87171', marginBottom: '1rem' }}>
          {error} — run <code>npm run dev</code> from the workspace root.
        </p>
      )}

      <ul style={{ listStyle: 'none', padding: 0, margin: 0 }}>
        {todos.map((t) => (
          <li
            key={t.id}
            style={{
              display: 'flex',
              alignItems: 'center',
              gap: 12,
              padding: '0.65rem 0',
              borderBottom: '1px solid #1e293b',
            }}
          >
            <input type="checkbox" checked={t.done} onChange={() => toggle(t)} />
            <span
              style={{
                flex: 1,
                textDecoration: t.done ? 'line-through' : 'none',
                color: t.done ? '#64748b' : '#e2e8f0',
              }}
            >
              {t.title}
            </span>
            <button
              type="button"
              onClick={() => remove(t)}
              style={{
                background: 'transparent',
                border: '1px solid #475569',
                color: '#94a3b8',
                borderRadius: 6,
                cursor: 'pointer',
                fontSize: '0.75rem',
              }}
            >
              Delete
            </button>
          </li>
        ))}
      </ul>
    </div>
  );
}

