files.package.json:
{
  "private": true,
  "name": "promora-fullstack-workspace",
  "workspaces": ["frontend", "backend"],
  "scripts": {
    "setup": "npm install && npm run db:push -w backend && npm run db:seed -w backend",
    "dev": "concurrently -k -n web,api -c cyan,magenta \"npm run dev -w frontend\" \"npm run dev -w backend\"",
    "dev:frontend": "npm run dev -w frontend",
    "dev:backend": "npm run dev -w backend",
    "db:studio": "npm run prisma:studio -w backend"
  },
  "devDependencies": {
    "concurrently": "^8.2.2"
  }
}
